async (params, browser) => {
  // Open Trello board
  await browser.open(`${params.board_url}`)

  // Let board load
  await browser.wait(3000)

  // Fetch board data via Trello API
  const result = await browser.evaluate(`const boardId = window.location.pathname.split('/')[2]; const resp = await fetch('/1/boards/' + boardId + '/lists?cards=open&card_fields=name,desc,labels,due,idMembers,shortUrl', { credentials: 'same-origin' }); if (!resp.ok) throw new Error('Board API error: ' + resp.status); const lists = await resp.json(); const result = lists.map(l => ({ list_name: l.name, list_id: l.id, cards: (l.cards || []).map(c => ({ name: c.name, description: c.desc?.substring(0, 200) || '', labels: (c.labels || []).map(lb => lb.name || lb.color), due: c.due || '', url: c.shortUrl || '' })) })); const totalCards = result.reduce((sum, l) => sum + l.cards.length, 0); return { board: boardId, list_count: result.length, total_cards: totalCards, lists: result }`)

  return result
}
